import axios from '@fs/zion-axios'
import { getSession, clearCachedSession } from '@fs/zion-session'
import { getFeatureFlag } from '@fs/zion-flags'
import deleteTFCache from './delete-tf-cache'

export async function getRoles() {
  const url = `/service/cmn/assignments/assignments`
  const { data } = await axios.get(url)
  return data.assignmentList
}

export async function getActiveRole() {
  try {
    const { session } = await getSession()

    const val = session.values && session.values.find((v) => v.name === 'AssignmentServiceAssignment')
    return val ? val.value : ''
  } catch (error) {
    console.error(error)
    return ''
  }
}

export async function enterRole(activeRole, role) {
  // Step 1: Delete the current session if switching to a new assignment
  const deleteSessionFlag = getFeatureFlag('home_adminMode_deleteSessionOnRoleSwitch')

  if (deleteSessionFlag.isOn && activeRole && activeRole !== role) {
    try {
      await axios.delete('/auth/session')
    } catch (error) {
      const status = error?.response?.status

      if (status !== 401 && status !== 404) {
        throw error
      }
    }
  }

  // Step 2: Clear cached session to ensure we get a fresh normal user session
  clearCachedSession()

  // Step 3: Call assignment-service with the normal user's session
  // The assignment-service will return a newly minted sessionId
  const { data: newSessionId, status } = await axios.put(
    `/service/cmn/assignments/assignments/${role}/new-access-token`,
    null,
    { headers: { Accept: 'text/plain' } }
  )

  // Step 4: Use the newly minted sessionId from assignment-service
  if (newSessionId) {
    await axios.post('/auth/session', { sessionId: newSessionId })
  }

  await deleteTFCache()
  status === 200 && typeof window !== 'undefined' && window.location.reload()
}

export async function exitRole() {
  await deleteTFCache()
  clearCachedSession()
  const { status } = await axios.delete('/auth/session')
  status === 204 &&
    typeof window !== 'undefined' &&
    window.location.assign(`/auth/familysearch/login?returnUrl=${encodeURIComponent(window.location.href)}`)
}
